#ifndef MAX_THREADS
#define MAX_THREADS 1024
#endif

typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    size_t ei = get_global_id(0);

    if (ei < (size_t)d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    size_t ei = get_global_id(0);

    if (ei < (size_t)d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_num_groups)
{
    (void)d_Ne;

    size_t bx = get_group_id(0);
    size_t tx = get_local_id(0);
    size_t lsize = get_local_size(0);
    size_t ei = bx * lsize + tx;

    __local fp d_psum[MAX_THREADS];
    __local fp d_psum2[MAX_THREADS];

    fp sum = 0.0f;
    fp sum2 = 0.0f;

    if (ei < (size_t)d_no) {
        sum = d_sums[ei * (size_t)d_mul];
        sum2 = d_sums2[ei * (size_t)d_mul];
    }

    d_psum[tx] = sum;
    d_psum2[tx] = sum2;

    barrier(CLK_LOCAL_MEM_FENCE);

    int nf = (int)(lsize - ((size_t)d_num_groups * lsize - (size_t)d_no));
    int df = 0;

    if (nf == (int)lsize) {

        for (int i = 2; i <= (int)lsize; i <<= 1) {
            if ((((int)tx) + 1) % i == 0) {
                d_psum[tx] += d_psum[tx - i / 2];
                d_psum2[tx] += d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == lsize - 1) {
            d_sums[bx * (size_t)d_mul * lsize] = d_psum[tx];
            d_sums2[bx * (size_t)d_mul * lsize] = d_psum2[tx];
        }
    }
    else {

        if ((int)bx != (d_num_groups - 1)) {

            for (int i = 2; i <= (int)lsize; i <<= 1) {
                if ((((int)tx) + 1) % i == 0) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == lsize - 1) {
                d_sums[bx * (size_t)d_mul * lsize] = d_psum[tx];
                d_sums2[bx * (size_t)d_mul * lsize] = d_psum2[tx];
            }
        }
        else {

            for (int i = 2; i <= (int)lsize; i <<= 1) {
                if (nf >= i) {
                    df = i;
                }
            }
            if (df == 0) {
                df = 1;
            }

            for (int i = 2; i <= df; i <<= 1) {
                if ((((int)tx) + 1) % i == 0 && (int)tx < df) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if ((int)tx == (df - 1)) {
                for (int i = (int)(bx * lsize) + df; i < (int)(bx * lsize) + nf; i++) {
                    d_psum[tx] += d_sums[i];
                    d_psum2[tx] += d_sums2[i];
                }

                d_sums[bx * (size_t)d_mul * lsize] = d_psum[tx];
                d_sums2[bx * (size_t)d_mul * lsize] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    size_t ei = get_global_id(0);

    if (ei < (size_t)Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[(size_t)iN[row] * (size_t)Nc + (size_t)col] - Jc;
        fp dS = d_I[(size_t)iS[row] * (size_t)Nc + (size_t)col] - Jc;
        fp dW = d_I[(size_t)row * (size_t)Nc + (size_t)jW[col]] - Jc;
        fp dE = d_I[(size_t)row * (size_t)Nc + (size_t)jE[col]] - Jc;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = 0.5f * G2 - 0.0625f * (L * L);
        fp den = 1.0f + 0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c = 1.0f / (1.0f + den);
        c = clamp(c, 0.0f, 1.0f);

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;
        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)iN;
    (void)jW;

    size_t ei = get_global_id(0);

    if (ei < (size_t)Ne) {
        int row = (int)(ei / (size_t)Nc);
        int col = (int)(ei % (size_t)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[(size_t)iS[row] * (size_t)Nc + (size_t)col];
        fp cW = d_c[ei];
        fp cE = d_c[(size_t)row * (size_t)Nc + (size_t)jE[col]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    size_t ei = get_global_id(0);

    if (ei < (size_t)d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
